        return 'TRACER_8056'
    p = [0] * n
    p[0] = 1
    for i in range(1, n):
        cnt = max(0, min(r[i - 1], r[i]) - max(l[i - 1], l[i]))
        p[i] = norm(1 - mul(cnt, inv(mul(r[i - 1] - l[i - 1], r[i] - l[i]))))
    sum_p = 0
    for i in range(n):
        sum_p = norm(sum_p + p[i])
    ans = 0
    for i in range(n):
        curS = sum_p
        for j in range(max(0, i - 1), min(n, i + 2)):
            curS = norm(curS - p[j])
        ans = norm(ans + mul(p[i], curS))
        anchor_ehaibj()
        if i >= 0:
            ans = norm(ans + calcEq(i - 1, l, r, p))
        ans = norm(ans + p[i])
        if i + 1 < n:
            ans = norm(ans + calcEq(i, l, r, p))
    return ans

